import { Validators } from '@angular/forms';
import { ChangeDetectorRef, Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup } from '@angular/forms';
import { MatTabChangeEvent } from '@angular/material/tabs';
import { Router } from '@angular/router';
import { ApiService } from 'app/shared/services/api.service';
import { LocalStoreService } from 'app/shared/services/local-store.service';
import { CorporateOnboardingService } from '../corporate-onboarding.service';
import { MatSnackBar } from '@angular/material/snack-bar';
import { DialogService } from 'app/shared/services/dialogs/dialog.service';

@Component({
  selector: 'app-onborading-primary',
  templateUrl: './onborading-primary.component.html',
  styleUrls: ['./onborading-primary.component.scss']
})
export class OnboradingPrimaryComponent implements OnInit {
  imgUrl: string | ArrayBuffer;
  selectedFiles: any;
  onboardingPrimary: FormGroup;

  companyNameArr:string[]=['ABC Bank','Yes Bank','No Bank'];
  categoryArr:string[]=['Privileged','Un Privileged'];
  countryArr:any[]=[];

  imageURL: any;
  profilePicture: any;
  profileImageExist: boolean = false;
  profileId: any;
  profileURL: any;
  customerId: any;
  constructor(private router: Router,
    private formBuilder: FormBuilder,
    private dialogService: DialogService,
    private corporateService: CorporateOnboardingService,
    private cdr: ChangeDetectorRef,
    private snack: MatSnackBar,
    private apiService: ApiService) { 
      this.onboardingPrimary = this.formBuilder.group({
        companyName: ['',[Validators.required]],
        category: ['',[Validators.required]],
        country: ['',[Validators.required]]
      })
      // this.corporateService.stepReady(this.onboardingPrimary, 'one')
    }

  ngOnInit(): void {
    this.imageURL = "not_available"
    console.log("imageurl", this.imgUrl)

   
    this.getCountryName("country");
  }

  previous(){
      this.dialogService.openCustomerType();
  }

  corporateChange(event) {
    this.selectedFiles = event.target.files[0];
    // Below part is used to display the selected image
    let reader = new FileReader();
    reader.readAsDataURL(event.target.files[0]);
    reader.onload = (event2) => {
      this.imgUrl = reader.result;
    }
  }

  public profileChange(event) {
    this.profilePicture = event.target.files[0];
    let reader = new FileReader();
    reader.readAsDataURL(event.target.files[0]);
    reader.onload = (event2) => {
      // this.imgUrl = reader.result;
      //  this.fun(event.target.files[0], this.profilePicture);
      this.imageURL = reader.result;
      this.profileImageExist = true;
    };
  }

  onSubmit(onboardingPrimary){
    console.log("onboardingPrimary :: ",onboardingPrimary);

    
    this.corporateService.saveOrUpdateCorporateAccountInfo(onboardingPrimary)
    .subscribe(data=>{
      console.log('data :: ', data);
      if(data != null){
        this.corporateService.sendCorporateAccountId(data.corporateId)
        this.snack.open('Data Saved' + ' !', 'OK', {
          duration: 4000,
          verticalPosition: 'top',
          horizontalPosition: 'right'
        });
        this.cdr.markForCheck();
        this.next()
      } else {
        this.snack.open('Not able to connect to server!', 'INTERNAL SERVER ERROR', {
          duration: 4000,
          verticalPosition: 'top',
          horizontalPosition: 'right'
        });
      }
    }, error => {
        console.log('error resp :: ',error);
        this.snack.open(`${error.error.message} `, 'OK', {
          duration: 4000,
          verticalPosition: 'top',
          horizontalPosition: 'right'
        });
    });
    
  }
  getProfileImage(customerId: any, document_type: number) {
    this.apiService.getCustomerDocuments(customerId, document_type).subscribe((data) => {
     console.log("data ::",data);
      if (data.length > 0) {
        this.profileId=data[0].id;
        this.imageURL=data[0].fileUrl;
      }
    });
  }

  deleteProfileImg(){
    this.imageURL="not_available";
    this.apiService.deleteCustomerDoc(this.customerId, this.profileId).subscribe((data) => {
    
  this.snack.open('Profile Image Deleted Successfully', 'OK', {
    duration: 4000,
    verticalPosition: 'top',
    horizontalPosition: 'right'
  });
  });

  }
  

  next() {
    this.corporateService.sendDisableMatTab({
      index: 1,
    });
    this.corporateService.setFinishFlag({
      finishFlag: false,
    });
  }

  getCountryName(key: string) {
    this.apiService.getDropDownValues(key).subscribe((data) => {
      console.log('datas :: ',data);
      this.countryArr = data;
      console.log('countryArr :: ',this.countryArr);
    });
  }
}
